import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Guide per Sviluppatori","description":"Le nostre guide scritte dalla community trattano di tutto, dalla creazione di una mod e la configurazione del tuo ambiente di sviluppo, fino ad argomenti avanzati come rendering, reti, generazione di dati, e altro.","frontmatter":{"title":"Guide per Sviluppatori","description":"Le nostre guide scritte dalla community trattano di tutto, dalla creazione di una mod e la configurazione del tuo ambiente di sviluppo, fino ad argomenti avanzati come rendering, reti, generazione di dati, e altro.","authors":["IMB11","its-miroma","itsmiir"],"authors-nogithub":["basil4088"],"resources":{"https://github.com/FabricMC":"Organizzazione FabricMC su GitHub","https://github.com/FabricMC/fabric-docs/tree/main/reference/latest":"ExampleMod a cui fa riferimento la documentazione"},"files":[]},"headers":[],"relativePath":"it_it/develop/index.md","filePath":"translated/it_it/develop/index.md","lastUpdated":1774519821000}`);var a={name:`it_it/develop/index.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Guide per Sviluppatori <a class="header-anchor" href="#h1" aria-label="Permalink to “Guide per Sviluppatori”">​</a></h1><p>Fabric è una toolchain di modding leggera per Minecraft: Java Edition, pensata per essere semplice e facile da usare. Permette agli sviluppatori di applicare modificazioni (&quot;mod&quot;) al gioco vanilla, aggiungendo nuove funzionalità o modificando meccaniche esistenti.</p><p>Questa documentazione ti guiderà nel mondo del modding con Fabric, partendo dal <a href="./getting-started/creating-a-project">creare la tua prima mod</a> e <a href="./getting-started/setting-up">configurare il tuo ambiente di sviluppo</a>, per arrivare ad argomenti avanzati come il <a href="./rendering/basic-concepts">rendering</a>, la <a href="./networking">gestione in rete</a>, la <a href="./data-generation/setup">generazione di dati</a>, e molto altro ancora.</p><p>Controlla la barra laterale per una lista delle pagine disponibili.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Nel caso ti servisse in qualunque momento, è disponibile una mod completamente funzionante con tutto il codice di questa documentazione nella <a href="https://github.com/FabricMC/fabric-docs/tree/main/reference/latest" target="_blank" rel="noreferrer">cartella <code>/reference</code> su GitHub</a>.</p></div><h2 id="prerequisites" tabindex="-1">Prerequisiti <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisiti”">​</a></h2><p>Prima d&#39;iniziare a far modding con Fabric, hai bisogno di avere una comprensione generale dello sviluppo con Java, e di conoscere la Programmazione Orientata agli Oggetti (OOP) a grandi linee.</p><p>Ecco qualche risorsa utile per imparare e familiarizzare con Java e OOP:</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Learn Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Introduction to OOP</a></li></ul><h2 id="what-does-fabric-offer" tabindex="-1">Cosa mi offre Fabric? <a class="header-anchor" href="#what-does-fabric-offer" aria-label="Permalink to “Cosa mi offre Fabric?”">​</a></h2><p>Il Progetto Fabric è centrato attorno a tre componenti principali:</p><ul><li><strong>Fabric Loader</strong>: un loader di mod flessibile, indipendente dalla piattaforma, progettato principalmente per Minecraft: Java Edition</li><li><strong>Fabric API</strong>: un insieme complementare di API e di strumenti che gli sviluppatori di mod possono usare</li><li><strong>Fabric Loom</strong>: un plugin <a href="https://gradle.org/" target="_blank" rel="noreferrer">Gradle</a>, che permette agli sviluppatori di sviluppare ed effettuare debug delle mod facilmente</li></ul><h3 id="what-does-fabric-api-offer" tabindex="-1">Cosa mi offre Fabric API? <a class="header-anchor" href="#what-does-fabric-api-offer" aria-label="Permalink to “Cosa mi offre Fabric API?”">​</a></h3><p>Fabric API fornisce un&#39;ampia gamma di API che si basano sulla funzionalità vanilla, per permettere sviluppo più semplice o più avanzato.</p><p>Per esempio, fornisce nuovi hook, eventi, utilità come i transitive access widener, accesso a registry interne tra cui la registry di oggetti compostabili, e altro.</p>`,15)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};